code.perFrame:
zoom = 1;
rot = 0;
dx = 0;
dy = 0;
sx = 1;
sy = 1;
warp = 1;
cx = 0.5;
cy = 0.5;
warp = 0;;
wave_r = wave_r + bass*.5;;
wave_g = wave_g + treb*.5;;
wave_b = wave_b + mid*.5;;
ib_r = ib_r + .4*sin(time*.222);;
ib_g = ib_g + .4*sin(time*.333);;
ib_b = ib_b + .4*sin(time*.111);;
ib_a = ib_a + .05*sin(time*.555);;
ib_size = ib_size + .24*sin(time*.444);;
bass_thresh = ((bass_att) > (bass_thresh))*2 + (1-((bass_att) > (bass_thresh)))*((bass_thresh-1.3)*0.96+1.3);;
cx_residual = ((bass_thresh) == (2))*0.016*sin(time*7) + (1-((bass_thresh) == (2)))*cx_residual;;
treb_thresh = ((treb_att) > (treb_thresh))*2 + (1-((treb_att) > (treb_thresh)))*((treb_thresh-1.3)*0.96+1.3);;
cy_residual = ((treb_thresh) == (2))*0.016*sin(time*7) + (1-((treb_thresh) == (2)))*cy_residual;;
mid_thresh = ((mid_att) > (mid_thresh))*2 + (1-((mid_att) > (mid_thresh)))*((mid_thresh-1.3)*0.96+1.3);;
rot_residual = ((mid_thresh) == (2))*0.016*sin(time*7) + (1-((mid_thresh) == (2)))*rot_residual;;
cx=cx_residual+sin(time*.888);;
cy=cy_residual+sin(time*.999);;
rot=rot_residual*3;
